#This is a function I created to generate mean, SD, and SE from a "data" for a "varname" based on "groupnames"
data_summary <- function(data, varname, groupnames){ summary_func <- function(x, col){ c(mean = mean(x[[col]], na.rm=TRUE), sd = sd(x[[col]], na.rm=TRUE), se = sd(x[[col]], na.rm=TRUE)/sqrt(length(x[[col]]))) } data_sum<-ddply(data, groupnames, .fun=summary_func, varname) data_sum <- plyr::rename(data_sum, c(varname="mean")) return(data_sum)
} #This is a function I created to generate sessions for each rat
session_count<-function(df) { seq(1, nrow(df), by=1)
} # ALL PRELIMINARY DATA CLEANING ----
FR_data <- read.csv(file="FR_data.csv")
FR_data_raw <- read.csv(file="FR_data.csv")
FR_data$fr<- as.character(FR_data$fr)
FR_data$comments<- as.character(FR_data$comments) #UNCOMMENT THE FOLLOWING WHEN COMBINING FR AND PR DATA
#PR_data <- read.csv(file="PR_data.csv")
#PR_data$fr<- as.character(PR_data$fr)
#FR_data<- rbind.fill(FR_data,PR_data) FR_data$fr<- factor(FR_data$fr, levels=c("1","5","10")) FR_data <- plyr::mutate(FR_data, activity=beam1+beam2+beam3+beam4)
FR_data <- mutate(FR_data, percent.active=active/(active+inactive))
FR_data <- mutate(FR_data, percent.inactive=inactive/(active+inactive)) FR_data$edate<-mdy(FR_data$edate) FR_data$subject<- as.factor(FR_data$subject)
FR_data$subject<-fct_inorder(FR_data$subject)
FR_data<- as.data.table(FR_data)
FR_data<- FR_data[order(FR_data$edate),]
FR_data<-FR_data %>% group_by(subject)%>% nest()
FR_data<-FR_data %>% mutate(session=map(data,session_count))
FR_data<-FR_data %>% unnest()
FR_data<-with(FR_data, FR_data[order(session),]) # TRIAL AND TIMEOUT ACTIVES for (q in (1:nrow(FR_data))) ({ if (FR_data$fr[q]==01) { FR_data$trial.active[q]=FR_data$reward[q] FR_data$timeout.active[q]=FR_data$active[q]-FR_data$trial.active[q] } else if (FR_data$fr[q]==5) { FR_data$trial.active[q]=FR_data$reward[q]*5 FR_data$timeout.active[q]=FR_data$active[q]-FR_data$trial.active[q] } else if (FR_data$fr[q]==10) { FR_data$trial.active[q]=FR_data$reward[q]*10 FR_data$timeout.active[q]=FR_data$active[q]-FR_data$trial.active[q] } else if (FR_data$fr[q]=="pr") { FR_data$trial.active[q]=FR_data$active[q]-FR_data$timeout.active[q] FR_data$timeout.active[q]=FR_data$timeout.active[q] }
}) FR_data<- FR_data %>% filter(str_detect(comments, "01")==FALSE)
FR_data <- FR_data %>% filter(str_detect(comments, "reinstatement")==FALSE) # SHINY UI HTML ----
options(contrasts=c("contr.sum", "contr.poly"))
