el1_9[order(session, subject),]) data15_1<-unite(level1_9, session, lever, col="session_lever", sep="_") data15_1<-dplyr::select(data15_1, subject, group, session_lever, presses) data15_1$session_lever<-data15_1$session_lever %>% factor() %>% fct_inorder() data16_1<-spread(data15_1, session_lever, presses) group<- data16_1$group subject<- data16_1$subject data16_1$group<-NULL data16_1$subject<-NULL data16_1<-t(apply(data16_1, 1, function(x) c(x[is.na(x)], x[!is.na(x)]))) data16_1<-data16_1[,apply(data16_1, 2, function(x) !any(is.na(x)))] data16_1<-data16_1[,(ncol(data16_1)-5):ncol(data16_1)] colnames(data16_1)<-c("x_active", "x_inactive", "y_active", "y_inactive", "z_active", "z_inactive") data16_1<-as.data.frame(data16_1) data16_1<- cbind(subject, group, data16_1) data16_1<- gather(data16_1, "session_lever", "presses", x_active:z_inactive) data16_1<- separate(data16_1, session_lever, c("session", "lever"), sep="_") data16_1$presses<- as.numeric(data16_1$presses) return(data16_1) }) #@last3 reactive.data12<- reactive({ lmer(presses ~ session*lever*group + (session|subject), data=reactive.data16()) }) #@last3 vals4 <- reactiveValues( keeprows4 = rep(TRUE, nrow(subset(FR_data, group==group_1))) ) #@univariate vals5 <- reactiveValues( keeprows5 = rep(TRUE, nrow(subset(FR_data, group==group_2))) ) #@univariate download.plot<- reactive({ ggplot(reactive.data1(), aes(x=session, y= mean, group = interaction(group), color=interaction(group))) + geom_errorbar(aes(ymin=mean-se, ymax=mean+se), width=.1, position=position_dodge(0.05)) + geom_point(aes(shape=fr), size = 5) + geom_line(aes(linetype=interaction(group)), size=1) + ggtitle(input$title) + ylab(input$y) + theme_classic() }) #----------------------------------------
