ize=20, face="bold"), axis.text = element_text(size = 20, face="bold"), axis.line = element_line(size = 1)) }) #@univariate output$plot5<- renderPlot({ keep5 <- subset(FR_data, group==group_2)[ vals5$keeprows5, , drop = FALSE] exclude5 <- subset(FR_data, group==group_2)[!vals5$keeprows5, , drop = FALSE] ggplot(keep5, aes_string(y=input$y, x="session")) + geom_boxplot(aes(fill=factor(session))) + geom_point() + labs(y=input$y, x="session") + theme_bw() + theme(axis.title.x = element_text(size=20, face="bold"), axis.title.y = element_text(size=20, face="bold"), axis.text = element_text(size = 20, face="bold"), axis.line = element_line(size = 1)) }) #@univariate output$int_plot<- renderPlot({ emmip(reactive.data14(), group ~ session | lever) }) #@anova output$residualplot1<- renderPlot({ qqnorm(residuals(reactive.data10())) qqline(residuals(reactive.data10())) }) #@anova output$residualplot2<- renderPlot({ plot(reactive.data10(), resid(., scaled=TRUE) ~ presses | group) }) #@anova output$int_plot2<- renderPlot({ emmip(reactive.data12(), group ~ session | lever) }) #@last3 output$residualplot3<- renderPlot({ qqnorm(residuals(reactive.data12())) qqline(residuals(reactive.data12())) }) #@last3 output$residualplot4<- renderPlot({ plot(reactive.data12(), resid(., scaled=TRUE) ~ presses | group) }) #@last3 #----------------------------------------
